{
    "$schema": "http://json-schema.org/draft-04/schema#",
    "title": "BootNotificationRequest",
    "type": "object",
    "properties": {
        "chargePointVendor": {
            "type": "string",
            "maxLength": 20
        },
        "chargePointModel": {
            "type": "string",
            "maxLength": 20
        },
        "chargePointSerialNumber": {
            "type": "string",
            "maxLength": 25
        },
        "chargeBoxSerialNumber": {
            "type": "string",
            "maxLength": 25
        },
        "firmwareVersion": {
            "type": "string",
            "maxLength": 50
        },
        "iccid": {
            "type": "string",
            "maxLength": 20
        },
        "imsi": {
            "type": "string",
            "maxLength": 20
        },
        "meterType": {
            "type": "string",
            "maxLength": 25
        },
        "meterSerialNumber": {
            "type": "string",
            "maxLength": 25
        }
    },
    "additionalProperties": false,
    "required": [
        "chargePointVendor",
        "chargePointModel"
    ]
}

{
    "$schema": "http://json-schema.org/draft-04/schema#",
    "title": "RemoteStartTransactionRequest",
    "type": "object",
    "properties": {
        "connectorId": {
            "type": "integer"
        },
        "idTag": {
            "type": "string",
            "maxLength": 20
        },
        "chargingProfile": {
            "type": "object",
            "properties": {
                "chargingProfileId": {
                    "type": "integer"
                },
                "transactionId": {
                    "type": "integer"
                },
                "stackLevel": {
                    "type": "integer"
                },
                "chargingProfilePurpose": {
                    "type": "string",
                    "enum": [
                        "ChargePointMaxProfile",
                        "TxDefaultProfile",
                        "TxProfile"
                    ]
                },
                "chargingProfileKind": {
                    "type": "string",
                    "enum": [
                        "Absolute",
                        "Recurring",
                        "Relative"
                    ]
                },
                "recurrencyKind": {
                    "type": "string",
                    "enum": [
                        "Daily",
                        "Weekly"
                    ]
                },
                "validFrom": {
                    "type": "string",
                    "format": "date-time"
                },
                "validTo": {
                    "type": "string",
                    "format": "date-time"
                },
                "chargingSchedule": {
                    "type": "object",
                    "properties": {
                        "duration": {
                            "type": "integer"
                        },
                        "startSchedule": {
                            "type": "string",
                            "format": "date-time"
                        },
                        "chargingRateUnit": {
                            "type": "string",
                            "enum": [
                                "A",
                                "W"
                            ]
                        },
                        "chargingSchedulePeriod": {
                            "type": "array",
                            "items": {
                                "type": "object",
                                "properties": {
                                    "startPeriod": {
                                        "type": "integer"
                                    },
                                    "limit": {
                                        "type": "number",
                                        "multipleOf": 0.1
                                    },
                                    "numberPhases": {
                                        "type": "integer"
                                    }
                                },
                                "required": [
                                    "startPeriod",
                                    "limit"
                                ]
                            }
                        },
                        "minChargingRate": {
                            "type": "number",
                            "multipleOf": 0.1
                        }
                    },
                    "required": [
                        "chargingRateUnit",
                        "chargingSchedulePeriod"
                    ]
                }
            },
            "required": [
                "chargingProfileId",
                "stackLevel",
                "chargingProfilePurpose",
                "chargingProfileKind",
                "chargingSchedule"
            ]
        }
    },
    "additionalProperties": false,
    "required": [
        "idTag"
    ]
}

{
    "description": "The options of a media object. An instance of <a href=\"#scene-media-options\">a scene media options object.</a>",
    "properties": {
        "autoPause": {
            "default": true,
            "description": "Does the video need to be paused automatically when the page is not visible anymore ?",
            "title": "Autopause",
            "type": "boolean"
        },
        "autoPlay": {
            "default": false,
            "description": "Does the video need to be played automatically at start ?",
            "title": "Autoplay",
            "type": "boolean"
        },
        "autoResume": {
            "default": false,
            "description": "Does the video need to be resumed automatically when the page is visible again ?",
            "title": "Autoresume",
            "type": "boolean"
        },
        "loop": {
            "default": false,
            "description": "Does the video need to be looped automatically at the end of playing ?",
            "title": "Loop",
            "type": "boolean"
        },
        "startTime": {
            "default": 0,
            "description": "Set the current position (in seconds) of the video playback.",
            "title": "Start Time",
            "type": "number"
        },
        "volume": {
            "default": 1,
            "description": "The volume of the media.",
            "maximum": 1,
            "minimum": 0,
            "title": "Volume",
            "type": "number"
        }
    },
    "title": "SceneMediaOptionsConfig",
    "type": "object"
}

{
    "description": "a payment transaction",
    "properties": {
        "sign": {
            "items": {
                "type": "string"
            },
            "minItems": 1,
            "type": "array",
            "_uniqueItems": true
        },
        "tx": {
            "properties": {
                "fee": {
                    "exclusiveMinimum": 0,
                    "type": "integer"
                },
                "from": {
                    "items": {
                        "type": "string"
                    },
                    "minItems": 1,
                    "type": "array",
                    "_uniqueItems": true
                },
                "id": {
                    "pattern": "^[0-9a-f]{64}$",
                    "type": "string"
                },
                "msg": {
                    "maxLength": 254,
                    "type": "string"
                },
                "to": {
                    "items": {
                        "properties": {
                            "address": {
                                "type": "string"
                            },
                            "amount": {
                                "exclusiveMinimum": 0,
                                "type": "integer"
                            }
                        },
                        "required": [
                            "address",
                            "amount"
                        ],
                        "type": "object"
                    },
                    "minItems": 1,
                    "type": "array"
                }
            },
            "required": [
                "id",
                "from",
                "to",
                "msg",
                "fee"
            ],
            "type": "object"
        }
    },
    "required": [
        "tx",
        "sign"
    ],
    "title": "Payment",
    "type": "object"
}

